import React, { useState, useEffect } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [filter, setFilter] = useState('');
    const [sortField, setSortField] = useState('name');
    const [sortDirection, setSortDirection] = useState('asc');

    // Function to handle filtering
    const applyFilter = () => {
        const filtered = records.filter(record => 
            record.name.toLowerCase().includes(filter.toLowerCase())
        );
        setRecords(filtered);
    };

    // Function to handle sorting
    const applySort = () => {
        const sorted = [...records];
        if (sortDirection === 'asc') {
            sorted.sort((a, b) => a[sortField].toLowerCase() > b[sortField].toLowerCase() ? 1 : -1);
        } else {
            sorted.sort((a, b) => a[sortField].toLowerCase() < b[sortField].toLowerCase() ? 1 : -1);
        }
        setRecords(sorted);
    };

